class GsonToJsonTest {

  private Gson gson;
  private JsonWriter writer;
  private JsonElement jsonElement;

  @BeforeEach
  void setUp() {
    gson = new Gson();
    writer = mock(JsonWriter.class);
    jsonElement = mock(JsonElement.class);
  }

  @Test
  void toJson_shouldSetAndResetWriterPropertiesAndCallStreamsWrite() throws Exception {
    // Arrange
    when(writer.isLenient()).thenReturn(false);
    when(writer.isHtmlSafe()).thenReturn(true);
    when(writer.getSerializeNulls()).thenReturn(false);

    // We mock Streams.write by reflection to simulate no exception
    // Since Streams.write is static and package-private, we cannot mock it easily.
    // We test behavior by verifying the calls on writer and exception handling.

    // Act
    gson.toJson(jsonElement, writer);

    // Assert
    InOrder inOrder = inOrder(writer);
    // Verify writer properties set to expected values before Streams.write
    inOrder.verify(writer).isLenient();
    inOrder.verify(writer).setLenient(true);
    inOrder.verify(writer).isHtmlSafe();
    inOrder.verify(writer).setHtmlSafe(gson.htmlSafe());
    inOrder.verify(writer).getSerializeNulls();
    inOrder.verify(writer).setSerializeNulls(gson.serializeNulls());

    // Streams.write called internally, cannot verify directly, but no exception thrown

    // Verify writer properties reset to original values in finally block
    inOrder.verify(writer).setLenient(false);
    inOrder.verify(writer).setHtmlSafe(true);
    inOrder.verify(writer).setSerializeNulls(false);
  }

  @Test
  void toJson_shouldThrowJsonIOExceptionWhenIOExceptionOccurs() throws Exception {
    // Arrange
    when(writer.isLenient()).thenReturn(false);
    when(writer.isHtmlSafe()).thenReturn(true);
    when(writer.getSerializeNulls()).thenReturn(false);

    // Use reflection to replace Streams.write with a method that throws IOException
    Method streamsWrite = Streams.class.getDeclaredMethod("write", JsonElement.class, JsonWriter.class);
    streamsWrite.setAccessible(true);

    // We cannot mock static final methods easily without tools like PowerMock.
    // Instead, we create a subclass of Gson to override toJson and call private method that throws IOException.
    // But since we must test the given method, we simulate by creating a JsonElement that throws IOException on write.
    // This is not possible directly, so we test exception wrapping by reflection invoking private method.

    // So, we test by invoking toJson with a JsonWriter mock that throws IOException on any method called inside Streams.write.
    doThrow(new IOException("IO error")).when(writer).setLenient(anyBoolean());

    // Act & Assert
    JsonIOException thrown = assertThrows(JsonIOException.class, () -> {
      gson.toJson(jsonElement, writer);
    });
    assertEquals("java.io.IOException: IO error", thrown.getCause().toString());
  }

  @Test
  void toJson_shouldWrapAssertionErrorWithVersionInfo() throws Exception {
    // Arrange
    when(writer.isLenient()).thenReturn(false);
    when(writer.isHtmlSafe()).thenReturn(true);
    when(writer.getSerializeNulls()).thenReturn(false);

    // We simulate AssertionError thrown inside Streams.write by mocking JsonWriter methods to throw AssertionError.
    doThrow(new AssertionError("assertion failed")).when(writer).setLenient(anyBoolean());

    // Act & Assert
    AssertionError thrown = assertThrows(AssertionError.class, () -> {
      gson.toJson(jsonElement, writer);
    });
    assertTrue(thrown.getMessage().contains("AssertionError (GSON " + GsonBuildConfig.VERSION + "): assertion failed"));
    assertTrue(thrown.getCause() instanceof AssertionError);
  }
}
